export const refreshTokenInterceptor: HttpInterceptorFn = (req, next) => {
  const auth = inject(AuthService);
  return next(req).pipe(
    catchError(err => {
      if (err.status === 401 && !req.url.includes('/refresh')) {
        return auth.refreshToken().pipe(
          switchMap(newToken => {
            const retryReq = req.clone({
              setHeaders: { Authorization: `Bearer ${newToken}` }
            });
            return next(retryReq);
          }),
          catchError(refreshErr => {
            auth.logout();
            return throwError(() => refreshErr);
          })
        );
      }
      return throwError(() => err);
    })
  );
};

// ✅ Service — feature-specific transformation
getUsers(): Observable<User[]> {
  return this.http.get<ApiResponse<User[]>>('/users').pipe(
    map(res => res.data)
  );
}

// ✅ Interceptor — common envelope unwrapping
export const responseInterceptor: HttpInterceptorFn = (req, next) => {
  return next(req).pipe(
    map(event => {
      if (event instanceof HttpResponse && event.body?.data) {
        return event.clone({ body: event.body.data });
      }
      return event;
    })
  );
};

